import os
import json
from google.cloud import storage, firestore, pubsub_v1

storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC")
PUBSUB_TOPIC_PATH = publisher.topic_path(os.environ["GCP_PROJECT"], PUBSUB_TOPIC) if PUBSUB_TOPIC else None

def process_gcs_file(data, context):
    bucket_name = data.get("bucket")
    file_name = data.get("name")

    if not bucket_name or not file_name:
        raise ValueError("Missing bucket or object name in event data")

    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    content = blob.download_as_text()

    doc_ref = firestore_client.collection("processed_files").document()
    doc_ref.set({
        "bucket": bucket_name,
        "file_name": file_name,
        "content": content,
    })

    if PUBSUB_TOPIC_PATH:
        message = {
            "bucket": bucket_name,
            "file_name": file_name,
            "status": "processed",
        }
        publisher.publish(PUBSUB_TOPIC_PATH, json.dumps(message).encode("utf-8"))

    return "OK"